import { KdsButton } from '@src/kds-components/kds-button/kds-button';
import { KdsMessage } from '@src/kds-components/kds-message/kds-message';

export const determineMessageDismissalButtonVariant = ({
  messageKind,
  messageVariant,
  messageInverseState
}: {
  messageKind: KdsMessage['kind'];
  messageVariant: KdsMessage['variant'];
  messageInverseState: KdsMessage['inverse'];
}) => {
  return messageKind === 'subtle' &&
  messageVariant === 'fill' &&
  !messageInverseState
    ? 'fill'
    : 'minimal';
};

export const dismissalButtonInMessageShouldBeInverse = ({
  messageInverseState,
  messageKind,
  messageVariant
}: {
  messageInverseState: KdsMessage['inverse'];
  messageKind: KdsMessage['kind'];
  messageVariant: KdsMessage['variant'];
}) => {
  // dismissal buttons in message-type components whose variant is fill and kind is prominent or dominant should use the opposite inverse state as the message
  // dismissal buttons in message-type components whose variant is fill and kind is subtle or alternate OR whose variant is border and is of any kind should inherit the same inverse state as the message
  return /dominant|prominent/gi.test(messageKind) && messageVariant === 'fill'
    ? !messageInverseState
    : messageInverseState;
};

export const loadingSpinnerInButtonShouldBeInverse = ({
  buttonInverseState,
  buttonKind
}: {
  buttonInverseState: KdsButton['inverse'];
  buttonKind: KdsButton['kind'];
}) => {
  // loading spinners in alternate and subtle kind buttons inherit the same inverse state as the button.
  // loading spinners in dominant and prominent kind buttons use the opposite inverse state as the button.
  return /dominant|prominent/gi.test(buttonKind)
    ? !buttonInverseState
    : buttonInverseState;
};
