import {
  Component,
  Event,
  EventEmitter,
  Prop,
  Element,
  h,
  Host,
  State
} from '@stencil/core';
import {
  determineMessageDismissalButtonVariant,
  dismissalButtonInMessageShouldBeInverse
} from '@src/utils/kds-utils/colorUtils';
import { iconPaletteMap } from '@src/utils/kds-utils/iconUtils';

const MessageConversionMap: Record<string, any> = {
  info: { kind: 'subtle', palette: 'informative', variant: 'fill', icon: 'kds-icon-info', role: 'dialog' },
  success:
    { kind: 'subtle', palette: 'positive', variant: 'fill', icon: 'kds-icon-success', role: 'dialog' },
  warning:
    { kind: 'subtle', palette: 'callout', variant: 'fill', icon: 'kds-icon-warning', role: 'alert' },
  error:
    { kind: 'subtle', palette: 'negative', variant: 'fill', icon: 'kds-icon-error', role: 'alert' }
};


interface KdsMessageHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

/**
 * Messages are a way to communicate with users through the UI.
 */
@Component({
  tag: 'kds-message',
  styleUrl: 'kds-message.css',
  shadow: false
})
export class KdsMessage {
  @Element() hostEl: KdsMessageHostElement;

  /** Sets the color palette. */
    // prettier-ignore
  @Prop({ mutable: true }) palette: 'neutral' | 'brand' | 'accent' | 'positive' | 'negative' | 'informative' | 'callout' | 'special' = 'accent';
  /** Sets the color kind. */
  @Prop({ mutable: true }) kind: 'success' | 'info' | 'warning' | 'error' | 'dominant' | 'prominent' | 'subtle' | 'alternate' = 'subtle';
  /** Sets the color variant. */
  @Prop({ mutable: true }) variant: 'fill' | 'border' = 'fill';
  /** Applies the inverse color styling. */
  @Prop({ mutable: true }) inverse: boolean = false;
  /** The role assignment for the message component. Use either "alert", "dialog", or "status." */
  @Prop({ mutable: true }) role: string | null = 'status';
  /** Sets the icon to display in the message header. */
  @Prop({ mutable: true }) icon?: string;

  /** Determines if closable. */
  @Prop() readonly closable: boolean = false;

  @State() ariaMessage: string;

  /** An event fired when a user closes the message. */
  @Event() messageClosed: EventEmitter;

  messageContentElement!: HTMLKdsTextElement;

  componentWillLoad() {
    this.ariaMessage = this.hostEl.textContent;

    if (MessageConversionMap[this.kind]) {
      this.palette = MessageConversionMap[this.kind].palette;
      this.variant = MessageConversionMap[this.kind].variant;
      this.inverse = MessageConversionMap[this.kind].inverse;
      this.icon = MessageConversionMap[this.kind].icon;
      this.kind = MessageConversionMap[this.kind].kind;
    }
  }

  onCloseButtonClick = () => {
    this.messageClosed.emit();
    this.hostEl.remove();
  };

  render() {
    const Icon =
      this.icon ||
      (iconPaletteMap[this.palette] &&
        `kds-icon-${iconPaletteMap[this.palette]}`) ||
      'kds-icon-info';
    const { closable, onCloseButtonClick } = this;
    const dismissalButtonClasses = {
      [`palette-${this.palette}`]: true,
      [`kind-${this.kind}`]: true,
      [`variant-${determineMessageDismissalButtonVariant({
        messageInverseState: this.inverse,
        messageKind: this.kind,
        messageVariant: this.variant
      })}`]: true,
      interactive: true,
      'as-inverse': dismissalButtonInMessageShouldBeInverse({
        messageInverseState: this.inverse,
        messageKind: this.kind,
        messageVariant: this.variant
      }),
      'kds-DismissalButton': true,
      'kds-Message-closeButton': true
    };

    return (
      <Host
        class={{
          'kds-Message': true,
          [`palette-${this.palette}`]: true,
          [`kind-${this.kind}`]: true,
          [`variant-${this.variant}`]: true,
          'as-inverse': this.inverse
        }}
        aria-label={`message: ${
          this.messageContentElement
            ? this.messageContentElement.innerText
            : this.ariaMessage
        }`}
        role={this.role}
      >
        <Icon class='kds-Message-icon' size='utility-s' />
        <kds-text
          ref={(el) => (this.messageContentElement = el)}
          class='kds-Message-content'
          size='s'
        >
          <slot />
        </kds-text>
        {closable && (
          <button
            aria-label='Close alert'
            data-testid='kds-Message-closeButton'
            onClick={onCloseButtonClick}
            class={{
              ...dismissalButtonClasses
            }}
          >
            <kds-icon-close size='xs' />
          </button>
        )}
      </Host>
    );
  }
}
